DROP TABLE IF EXISTS `inventory_event`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `inventory_event` (
  `inventory_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `snapshot_month` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `item_type` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `item_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `item_code` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `item_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `warehouse_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `warehouse_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `batch_number` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `quantity` int(11) DEFAULT NULL,
  `unit_price` double DEFAULT NULL,
  `total_price` double DEFAULT NULL,
  `earliest_storage_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `max_storage_age` int(11) DEFAULT NULL,
  `storage_reason` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `storage_note` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `consumption_path` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `created_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `status` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

