CREATE TABLE `material_procurement_event` (
  `procurement_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `procurement_number` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `procurement_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_code` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `material_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `material_code` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `material_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `warehouse_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `warehouse_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `quantity` int(11) DEFAULT NULL,
  `unit_price` double DEFAULT NULL,
  `total_amount` double DEFAULT NULL,
  `currency` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `tax_rate` double DEFAULT NULL,
  `payment_terms` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `logistics_provider` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `tracking_number` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `ship_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `estimated_delivery_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `actual_delivery_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `inspection_status` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `notes` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `created_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `status` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

