--
-- Table structure for table `purchase_order_event`
--

DROP TABLE IF EXISTS `purchase_order_event`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `purchase_order_event` (
  `purchase_order_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `purchase_order_number` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `document_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `material_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `material_code` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `material_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `purchase_quantity` int(11) DEFAULT NULL,
  `unit_price_tax` double DEFAULT NULL,
  `total_amount_tax` double DEFAULT NULL,
  `unit_price_no_tax` double DEFAULT NULL,
  `total_amount_no_tax` double DEFAULT NULL,
  `tax_rate` double DEFAULT NULL,
  `document_status` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `required_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `planned_arrival_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `accumulated_arrival_tax` double DEFAULT NULL,
  `accumulated_storage_tax` double DEFAULT NULL,
  `payment_terms` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_level` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `risk_level` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `buyer` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `created_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `status` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `purchase_order_event`
--

LOCK TABLES `purchase_order_event` WRITE;
/*!40000 ALTER TABLE `purchase_order_event` DISABLE KEYS */;
