DROP TABLE IF EXISTS `supplier_entity`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `supplier_entity` (
  `supplier_id` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_code` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_short_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_category` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `supplier_tier` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `primary_contact` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `contact_phone` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `contact_email` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `registered_address` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `country` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `city` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `settlement_currency` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `default_tax_rate` double DEFAULT NULL,
  `payment_terms` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `lead_time_avg` int(11) DEFAULT NULL,
  `risk_level` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `is_active` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `established_year` int(11) DEFAULT NULL,
  `annual_capacity` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `created_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `status` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

