  `province` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `country` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `postal_code` int(11) DEFAULT NULL,
  `latitude` double DEFAULT NULL,
  `longitude` double DEFAULT NULL,
  `total_area_sqm` int(11) DEFAULT NULL,
  `storage_area_sqm` int(11) DEFAULT NULL,
  `warehouse_height` int(11) DEFAULT NULL,
  `storage_capacity_cbm` int(11) DEFAULT NULL,
  `pallet_positions` int(11) DEFAULT NULL,
  `temperature_control` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `temperature_range` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `humidity_control` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `humidity_range` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `has_cold_storage` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `fire_protection_level` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `security_system` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `has_wms` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `wms_system` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `automation_level` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `has_agv` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `agv_count` int(11) DEFAULT NULL,
  `has_conveyor` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `has_sorting_system` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `has_rfid` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `established_year` int(11) DEFAULT NULL,
  `operation_hours` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `max_daily_throughput` int(11) DEFAULT NULL,
  `throughput_unit` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `manager_name` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `manager_phone` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `manager_email` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `employee_count` int(11) DEFAULT NULL,
  `certifications` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `quality_standards` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `created_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `last_inspection_date` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL,
  `status` varchar(50) COLLATE utf8_unicode_ci DEFAULT NULL
) ENGINE=MyISAM DEFAULT CHARSET=utf8 COLLATE=utf8_unicode_ci;
